(()=>{(function(){var m=document.getElementById('guest-modal');if(!m)return;if(m.parentElement!==document.body)document.body.appendChild(m);m.addEventListener('click',function(e){if(e.target===m&&window.closeGuestModal)window.closeGuestModal()})})();window.showGuestModal=function(){var m=document.getElementById('guest-modal');if(m)m.style.display='flex'};window.closeGuestModal=function(){var m=document.getElementById('guest-modal');if(m)m.style.display='none'};window.agreeGuestLogin=function(){window.closeGuestModal();if(window.startGuestLogin)window.startGuestLogin()};window.startGuestLogin=function(){document.body.classList.add('guest-mode');window.__loadCoreCss&&window.__loadCoreCss();var u={fname:'ضيف',lname:'',fullName:'ضيف',avatar:'',role:'guest',email:''};try{sessionStorage.setItem('currentUser',JSON.stringify(u));sessionStorage.setItem('isAdmin','false');localStorage.setItem('guest-mode','true');sessionStorage.setItem('guest-mode','true')}catch(e){console.error('[guest] failed to save session',e);return}var l=document.getElementById('login-screen'),d=document.getElementById('dashboard-view'),n=document.getElementById('ios-bottom-nav'),q=document.getElementById('quiz-container'),w=document.getElementById('welcome-msg');if(l)l.classList.add('hidden');if(d)d.classList.remove('hidden');if(n)n.classList.remove('hidden');if(q)q.classList.add('hidden');if(w)w.innerText='مَرْحَبًا بِكَ يَا ضَيْفَنَا الكَرِيم — الدخول تجريبي ولن تُحفظ الدرجات';console.log('[guest] ✓ تم الدخول كضيف — سيبدأ تحميل البيانات...');if(typeof window.loadApp==='function'){try{window.loadApp()}catch(e){console.warn('[guest] loadApp failed',e)}}else{if(typeof window.navToHome==='function')try{window.navToHome()}catch(e){};if(typeof window.renderDashboard==='function')try{window.renderDashboard()}catch(e){}}};})();